  ('disabled-64311456-moex-00375', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依國家賠償法規定，關於請求國家賠償之敘述，下列何者錯誤？', '["國家賠償之請求，起訴前應先以書面向賠償義務機關為之", "於賠償義務機關有爭議時，得請求其上級機關確定之", "賠償義務機關拒絕賠償，自拒絕之日起30日後始得提起損害賠償之訴", "損害賠償之訴，除依本法規定外，適用民事訴訟法之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
